/* techniques q05 (82 mục) — engine-API đợt 441-457 Ch.457 — ra-soat: gộp thẻ trùng - gop trung 2026-06-24 - gop theo danh sach 2026-06-25 */
window.__LIBQ=window.__LIBQ||{};window.__LIBQ["tien-nghich"]=window.__LIBQ["tien-nghich"]||{};window.__LIBQ["tien-nghich"]["q05"]=window.__LIBQ["tien-nghich"]["q05"]||{};window.__LIBQ["tien-nghich"]["q05"]["techniques"]={"updatedAt":"2026-06-16","count":80,"techniques":[{"id":"chu-tuoc-tran","name":"Chu Tước trận","cn":"","aliases":["Chu Tước kỳ trận"],"loai":"khac","loaiLabel":"Trận pháp","phamCap":"Đại trận hộ vệ cấp quốc","hePhai":"Chu Tước quốc / phe Chu Tước Tử","soHuu":["Kiền Phong"],"blurb":"Đại trận bao phủ toàn bộ Chu Tước đại lục, Kiền Phong có thể chuyển về quấn quanh thân để hộ thể, kiên cố tới mức phải dùng đệ tứ chủ hồn mới phá nổi.","detail":"Chu Tước trận là kỳ trận trấn giữ toàn bộ Chu Tước đại lục. Khi lâm nguy, Kiền Phong khoanh chân bấm quyết, chuyển lực trận từ đại lục về bao phủ chính thân mình làm lá chắn hộ thân. Trận khởi động phun ra vô số tia sáng xanh như cầu vồng rẽ đất, cuộn thành lốc xoáy quét ngang để chống đỡ công kích. Sức phòng ngự cực mạnh: dù đối mặt uy lực hàng triệu hồn phách tự nổ của Thập Ức Tôn Hồn Phiên, Kiền Phong chỉ bị chấn thương phun một ngụm máu mà vẫn giữ được mạng. Chính nhờ Chu Tước trận hộ thân mà Độn Thiên đánh giá phải dùng tới đệ tứ chủ hồn mới có thể giết được Kiền Phong, nên đành buông tay không hạ sát.","nguon":["@c0392"]},{"id":"ho-son-dai-tran-luyen-hon-tong","name":"Hộ sơn đại trận (Luyện Hồn Tông)","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"","hePhai":"Luyện Hồn Tông","soHuu":["Luyện Hồn Tông"],"blurb":"Đại trận bảo vệ núi của Luyện Hồn Tông, cản yêu thú bên ngoài tiến vào.","detail":"Hộ sơn đại trận là trận pháp phòng vệ trùm quanh sơn môn của Luyện Hồn Tông trên Chu Tước Tinh. Khi Vương Lâm tiến hành Anh Biến, thân thể tản ra hương khí dẫn dụ yêu thú và lệ hồn đến đoạt xá; Độn Thiên dựa vào hộ sơn đại trận này để cản yêu thú bên ngoài, kết hợp Tôn Hồn Phiên xử lý lệ hồn. Trong toàn Chu Tước Tinh chưa thấy yêu thú nào đẩy lui được Độn Thiên dưới sự che chắn của đại trận.","nguon":["@c0393"]},{"id":"chu-tuoc-thanh-hoa","name":"Chu Tước thánh hỏa","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Vấn Đỉnh Hậu Kỳ","hePhai":"Chu Tước Tinh","soHuu":["Chu Tước Tử"],"blurb":"Thần thông của Chu Tước Tử: đốt một lông chim đỏ làm trung tâm, bùng lửa cuồng mãnh phủ trăm dặm, vật gì dính lửa lập tức biến mất.","detail":"Chu Tước thánh hỏa là thần thông trấn phái của Chu Tước Tử, người đứng đầu Chu Tước Tinh. Khi thi triển, hắn lấy một lông chim đỏ làm chất xúc tác; lông chim cháy rồi vỡ vụn, từ đó bùng lên một biển lửa cuồng mãnh bao phủ phạm vi tới trăm dặm. Uy lực kinh người: mọi thứ bị lửa dính vào đều lập tức biến mất, kể cả tu sĩ đang ở trong vùng. Trong một lần thi triển, lửa đã phủ trùm cả khu vực Vương Lâm đang bế quan tiến hành Anh Biến, khiến Vương Lâm cũng bị cuốn vào và biến mất không rõ sống chết. Lửa này cường đại đến mức Độn Thiên phải dùng ba mảnh cổ sắc ngọc giản lượn vòng quanh thân mới khó khăn ngăn được.","nguon":["@c0394"]},{"id":"chu-tuoc-huyen-an","name":"Chu Tước huyền ấn","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Vấn Đỉnh Hậu Kỳ","hePhai":"Chu Tước Tinh","soHuu":["Chu Tước Tử"],"blurb":"Thần thông bí truyền chỉ các đời Chu Tước Tử nắm giữ, cảm ngộ từ di vật của đệ nhất Chu Tước Tử; gồm hai ấn công và thủ, dùng sẽ hao tổn nhất định.","detail":"Chu Tước huyền ấn không phải do tu luyện mà có, mà do các đời Chu Tước Tử cảm ngộ từ di vật của đệ nhất Chu Tước Tử để lại trong mộ. Ấn này do tu chân liên minh ban cho khi Chu Tước quốc trở thành tu chân quốc cấp sáu. Nó không nâng cao bản lãnh người dùng nhưng vô cùng huyền diệu, chia làm hai ấn: ấn công không gì không phá, ấn th��� phòng ngự mạnh hơn cả Chu Tước kỳ trận. Mỗi thế hệ trong số tu chân tinh cấp sáu trở lên chỉ có một người được nắm giữ; khi người sau kế tục thì người trước mất thần thông này. Khi dùng ấn sẽ gây hao tổn nhất định cho người thi triển. Trong trận chiến với Độn Thiên, Chu Tước Tử bị ép dùng ấn phòng thủ để chống chín phi kiếm tiên lực — tiếng nổ kinh thiên động địa xuyên suốt Chu Tước đại lục; hắn không bị thương nhưng sắc mặt tái nhợt, mất hết vẻ phiêu dật.","nguon":["@c0394"]},{"id":"tu-tinh-chi-tam","name":"Tu tinh chi tâm","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Cực hiếm — đổi mạng","hePhai":"Chu Tước Sơn","soHuu":["Chu Tước Tử"],"blurb":"Bí thuật mở khóa bằng cách hiến tế tuổi thọ, đoạt được đình chỉ ý cảnh khiến mọi sinh linh trong trăm trượng ngừng bất động trong nháy mắt.","detail":"Tu tinh chi tâm là một bí thuật chí mệnh: muốn mở ra phải hiến tế tuổi thọ làm cái giá, và theo điển tịch ghi chép thì lúc mở tu tinh chi tâm cũng chính là lúc tuổi thọ kết thúc. Khi Chu Tước Tử thi triển, lão lấy nắm bùn đen, cắn lưỡi phun máu lên dẫn khói đen tạo thành một ký hiệu kỳ lạ, tự xưng là một đời Chu Tước Tử rồi hiến tế chín phần mười tuổi thọ còn lại để mở tu tinh chi tâm. Nhờ đó lão đoạt được ‘đình chỉ ý cảnh’ do tu chân liên minh ban: ký hiệu bay ra trước mặt ba trượng rồi biến mất, khiến mọi sinh linh trong phạm vi trăm trượng ngừng lại bất động trong nháy mắt — đủ để lão chụp lấy đệ tứ hồn vào trong tay.","nguon":["@c0395"]},{"id":"phu-tran-diet-chu-tuoc-quoc","name":"Phù trận diệt Chu Tước quốc","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"","hePhai":"Tiên Di Tộc","soHuu":["Chu Tước Tử (Ngũ tổ Tiên Di Tộc)"],"blurb":"Đại trận phù văn quy mô lớn của Tiên Di Tộc, bày tại màn sương đen phía đông Chu Tước đại lục nhằm diệt Chu Tước quốc.","detail":"Vô số người Tiên Di Tộc khoanh chân ngồi ở trung tâm màn sương đen, đọc chú ngữ quỷ dị và thôi thúc sức mạnh phù văn trong cơ thể. Phù văn xuất ra tụ lại, quay vòng quanh bốn phía với tốc độ cực nhanh, mỗi vòng quay lại giãn rộng thêm. Cứ mỗi hai canh giờ, khi sức mạnh phù văn của một đám tộc nhân hao tổn hết thì đám khác thay thế, chú ngữ vận hành liên tục không gián đoạn. Quá trình này duy trì liên tục mấy tháng. Trận sinh ra lực cản phù văn ngăn người ngoài, phải mở thông đạo mới cho vào được. Bốn phân nhánh cây tổ linh phối hợp vây quanh Chu Tước đại lục, khiến Chu Tước quốc gần như chắc chắn bị diệt.","nguon":["@c0396"]},{"id":"trang-thai-cuong-ngao-vuong-lam","name":"Trạng thái cuồng ngạo của Vương Lâm","cn":"","loai":"than-thong","loaiLabel":"Thần thông / Khí tức","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Trạng thái khí tức quỷ dị cực điểm của Vương Lâm khi xuất hiện ở Luyện Hồn Tông, cuồng ngạo vô pháp vô thiên.","detail":"Khi xuất hiện tại Luyện Hồn Tông, Vương Lâm bao trùm trong hào quang bảy màu, tóc dài tự bay, phát tán khí tức quỷ dị cực điểm. Quanh thân là quầng sáng lam sẫm âm hàn có thể đóng băng mọi thứ, thân thể trong suốt sáng bóng, đôi mắt mang tà khí cực thịnh (so với tà khí trong mắt Kiền Phong thì như đom đóm với trăng sáng). Khí tức toát ra cực kỳ cuồng ngạo, vô pháp vô thiên, khiến Chu Tước Tử đời thứ mười bốn khiếp sợ toát mồ hôi lạnh, ngờ rằng người trước mắt không phải Vương Lâm thường ngày — gợi ý một thân phận hoặc ý chí khác đang chi phối.","nguon":["@c0396"]},{"id":"truc-co-dai-phap","name":"Trúc Cơ đại pháp","cn":"","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Đại pháp Trúc Cơ mà Vương Lâm đoạt được nhờ sự gợi ý của Tư Đồ Nam thuở đầu tu hành.","detail":"Trúc Cơ đại pháp là công pháp giúp tu sĩ vượt qua giai đoạn Trúc Cơ. Trong dòng hồi tưởng về ân tình cũ, Tư Đồ Nam nhắc lại rằng chính hắn từng gợi ý để Vương Lâm đoạt được Trúc Cơ đại pháp này, một trong những bước ngoặt quan trọng giúp Vương Lâm đặt nền móng tu tiên.","nguon":["@c0397"]},{"id":"thuat-hap-thu-cay-than-tien-di","name":"Thuật thần thông hấp thu sức mạnh cây thần (Tiên Di Tộc)","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Chu Tước Tử (đệ nhất)","soHuu":["Tư Đồ Nam"],"blurb":"Thần thông do đệ nhất Chu Tước Tử nghiên cứu, nhờ cây thần của Tiên Di Tộc hấp thu một sức mạnh kỳ dị; có một sơ hở trí mạng.","detail":"Thuật thần thông được đệ nhất Chu Tước Tử nghiên cứu, cho phép mượn cây thần của Tiên Di Tộc để hấp thu một loại sức mạnh kỳ dị. Khi Tư Đồ Nam phát hiện người Tiên Di Tộc đang hiến tế tổ linh, lão nhớ tới thuật này và quyết định thi triển: lão xin Vương Lâm một khối tiên ngọc, hút lấy tiên lực để chuẩn bị. Lão thừa nhận thuật có một sơ hở trí mạng, nhưng với tu vi và tình cảnh hiện tại của lão thì có thể tránh được.","nguon":["@c0398"]},{"id":"bi-thuat-nuoi-cay-luan-hoi-thu-to-linh","name":"Bí thuật nuôi cấy Luân Hồi thụ tổ linh","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Bí thuật trấn tộc Tiên Di Tộc","hePhai":"Tiên Di Tộc","soHuu":["Ngũ tổ (Tiên Di Tộc)","Tứ tổ (Tiên Di Tộc)"],"blurb":"Bí thuật trấn tộc của Tiên Di Tộc dùng để nuôi cấy Luân Hồi thụ — vật tổ linh hiếm có sinh ra thập diệp thuật chú sư.","detail":"Bí thuật cốt lõi của Tiên Di Tộc. Khởi đầu, một kim mang to bằng nắm tay được ấn vào ngực thi thể Cự Ma Tộc; kim mang sáng dần như mặt trời, thi thể khô héo trở thành ‘đất’ nuôi cây, trong mười nhịp thở hóa thây khô rồi tan thành tro. Sau đó kim mang vỡ vụn, một Luân Hồi thụ cao trăm trượng mọc lên từ đất cắm thẳng lên trời, phát ra sóng xung lực phủ cả một phương đại lục. Khi tổ linh trưởng thành, phối hợp bí thuật sẽ có linh thể từ hư vô giáng lâm, kết hợp thành một thập diệp thuật chú sư. Mấy vạn năm Tiên Di Tộc chỉ nuôi cấy được năm cây tổ linh duy nhất, cho thấy độ quý hiếm và công phu của bí thuật này.","nguon":["@c0399"]},{"id":"man-suong-den-ngu-to","name":"Màn sương đen của ngũ tổ","cn":"","loai":"bi-thuat","loaiLabel":"Pháp thuật / Trận","phamCap":"Pháp thuật phòng thủ cấp lão tổ","hePhai":"Tiên Di Tộc","soHuu":["Ngũ tổ (Tiên Di Tộc)"],"blurb":"Pháp thuật của ngũ tổ Tiên Di Tộc, vung tay tạo màn sương đen lớn bao bọc chiến trường, bên trong tiên lực phát lực xung kích.","detail":"Ngũ tổ Tiên Di Tộc vung tay tạo ra một màn sương đen lớn bao bọc cả mình và đối thủ cùng vùng chiến trường. Bên trong màn sương, ánh sáng pháp bảo cùng tiên lực phát lực xung kích mạnh mẽ, khiến tu sĩ và tộc nhân Tiên Di Tộc ở gần đều thân vỡ mà chết. Thi Âm Tông cũng dùng màn sương đen tương tự để xuất hiện và biến mất khỏi chiến trường.","nguon":["@c0399"]},{"id":"suong-cuu-le","name":"Sương Cửu Lê / khí Cửu Lê","cn":"","loai":"bi-thuat","loaiLabel":"Cấm chế · sức mạnh cổ xưa","phamCap":"Cổ xưa thần bí","hePhai":"Tiểu Bắc Viêm Cực","soHuu":["Tư Đồ Nam"],"blurb":"Sương lạnh màu lam ở nơi cực lạnh cực nóng, vừa hủy diệt sinh linh vừa hấp thu đông lạnh vật không thể phá hủy.","detail":"Sương Cửu Lê (khí Cửu Lê) là màn sương lạnh màu lam u ám chỉ xuất hiện ở nơi cực lạnh cực nóng, mang sức mạnh cổ xưa thần bí. Nó vừa hủy diệt sinh linh, vừa hấp thu và đông lạnh trong thời gian ngắn cả những vật không thể phá hủy. Khí Cửu Lê tràn ngập Tiểu Bắc, là một trong các cấm chế tự nhiên nơi đây và liên tục xông lên luyện hóa ma đồng bị nhốt. Tư Đồ Nam — từng tu luyện rất lâu tại Tiểu Bắc Viêm Cực — có thể điều khiển nó: hắn quát ‘Sương Cửu Lê’ khiến đám sương đen bao bọc ma đồng bay tới bao bọc cả hắn lẫn tứ tổ Tiên Di Tộc rồi kéo về phía viêm băng đang vây khốn ma đồng.","nguon":["@c0400"]},{"id":"huyet-chi-quang-cuc-viem","name":"Huyết chi quang của Cực Viêm","cn":"","loai":"bi-thuat","loaiLabel":"Cấm chế · bạch quang","phamCap":"Cấm chế tự nhiên","hePhai":"Tiểu Bắc Viêm Cực","soHuu":["Tư Đồ Nam"],"blurb":"Ánh bạch quang cực nóng vô hại với vật không huyết dịch nhưng khiến sinh vật có huyết dịch sôi trào, thiêu đốt chưa đến mười nhịp thở là tử vong.","detail":"Huyết chi quang là một trong các cấm chế tự nhiên của Tiểu Bắc Viêm Cực. Khi kích hoạt, trời đất lóng lánh bạch quang chói mắt. Ánh sáng cực nóng này vô tác dụng với vật không có huyết dịch, nhưng sinh vật có huyết dịch bị chiếu vào sẽ sôi trào, thiêu đốt chưa đến mười nhịp thở liền tử vong. Khi Tư Đồ Nam bấm quyết niệm chú kích hoạt cấm chế, huyết chi quang chiếu lên tứ tổ Tiên Di Tộc khiến da hắn dâng hồng quang — buộc tứ tổ phải xoa người tạo phù văn lớn đẩy tan bạch quang.","nguon":["@c0400"]},{"id":"cay-cuu-diep","name":"Cây cửu diệp","cn":"","loai":"than-thong","loaiLabel":"Thần thông phòng vệ","phamCap":"","hePhai":"Tiên Di Tộc","soHuu":["Tứ tổ Tiên Di Tộc"],"blurb":"Cây chín lá hiện ra ở mi tâm, đẩy lui kẻ đoạt xá chui vào cơ thể.","detail":"Cây cửu diệp (cây chín lá) là thần thông phòng vệ của tứ tổ Tiên Di Tộc. Khi Tư Đồ Nam xuyên qua tơ phù văn chui thẳng vào cơ thể tứ tổ, tứ tổ chấn động quát ‘Cút ra’ rồi vỗ trán hiện cây cửu diệp ở mi tâm, đẩy Tư Đồ Nam chui ra khỏi cơ th�� mình. Cửu diệp gắn liền với đặc trưng cây thần/tổ linh của Tiên Di Tộc.","nguon":["@c0400"]},{"id":"bi-thuat-doat-lai-to-linh","name":"Bí thuật đoạt lại tổ linh","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật Tiên Di Tộc","phamCap":"","hePhai":"Tiên Di Tộc","soHuu":["Tứ tổ Tiên Di Tộc"],"blurb":"Bí thuật của Tiên Di Tộc cho phép đoạt lại tổ linh từ kẻ đã nuốt, với điều kiện tổ linh chưa bị luyện hóa.","detail":"Bí thuật đoạt lại tổ linh là tuyệt học của Tiên Di Tộc. Khi tổ linh bị kẻ khác nuốt, người Tiên Di Tộc có thể đuổi kịp và thi triển bí thuật để đoạt tổ linh trở về cơ thể bản tộc — nhưng chỉ hiệu nghiệm khi tổ linh chưa bị kẻ nuốt luyện hóa. Vì điều kiện này mà tứ tổ Tiên Di Tộc kiên trì đuổi theo Tư Đồ Nam — kẻ đã nuốt tổ linh — không bỏ, tạo áp lực thời gian cho cuộc rượt đuổi.","nguon":["@c0400"]},{"id":"tran-phap-nuoi-duong-ma-dong","name":"Trận pháp nuôi dưỡng ma đồng","cn":"","loai":"khac","loaiLabel":"Trận pháp đặc biệt","phamCap":"","hePhai":"Thi Âm Tông","soHuu":["Tôn Thái"],"blurb":"Trận pháp đặc biệt nuôi dưỡng dị vật ma đồng; vật không được rời trận quá lâu.","detail":"Trận pháp nuôi dưỡng ma đồng là trận pháp đặc biệt do Tôn Thái dùng để nuôi dưỡng dị vật (ma đồng) — vật trời sinh để người đoạt xá. Ma đồng tế luyện hơn ngàn năm thành thi thể có bản lãnh Anh Biến Trung Kỳ, nhưng phải đặt trong trận pháp nuôi dưỡng này, không được rời trận quá lâu nếu không sẽ mất ổn định. Đây là lý do khi đi tiên giới Tôn Thái không mang ma đồng theo mà để lại ở Chu Tước Tinh.","nguon":["@c0400"]},{"id":"thuat-than-thong-te-troi","name":"Thuật thần thông tế trời","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Thượng cổ bí pháp","hePhai":"Tu chân liên minh","soHuu":["Tu chân liên minh"],"blurb":"Thuật thần thông tế trời mà tu chân liên minh dùng để luyện tạo ra Tu Tinh Chi Tinh.","detail":"Là thuật thần thông cấp tế trời do tu chân liên minh nắm giữ, dùng để tạo ra Tu Tinh Chi Tinh — vật được ban cho mọi tu chân quốc đạt cấp sáu. Thành phẩm của thuật này khi mở ra bằng bí pháp sẽ sinh thành một loại sức mạnh kỳ dị bao phủ toàn bộ tu chân tinh, khiến mọi sinh mệnh sinh ra trên tinh cầu — yêu thú hay phàm nhân — đều thiếu đi một mệnh hồn bị Tu Tinh Chi Tinh hấp thụ. Chính nhờ thuật này mà tu chân liên minh trao cho tu chân quốc cấp sáu quyền lực khống chế tối thượng đối với toàn thể sinh linh trong tinh cầu, làm cơ sở cho địa vị đế vương của họ.","nguon":["@c0401"]},{"id":"chu-tuoc-quyet","name":"Chu Tước quyết","cn":"","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"","hePhai":"Chu Tước quốc","soHuu":["Kiền Phong"],"blurb":"Pháp quyết các đời Chu Tước Tử tu luyện, thoát thai từ Chu Tước Ấn của đệ nhất Chu Tước Tử; tăng tốc độ tu luyện và hợp nhất với Tu Tinh Chi Tâm. (+) Công pháp do Kiền Phong tu luyện, được nghi liên quan tới việc Chu Tước Tử chuẩn bị đoạt xá để kéo dài tuổi thọ. [CAN-SOAT-GOP]","detail":"Chu Tước quyết là công pháp mà Kiền Phong — đệ tử của Chu Tước Tử — tu luyện. Khi Vân Tước Tử bàn về kế hoạch Chu Tước, hắn nghi ngờ rằng việc Chu Tước Tử cho Kiền Phong tu Chu Tước quyết không đơn thuần là truyền dạy: rất có thể đương kim Chu Tước Tử đang chuẩn bị Kiền Phong làm thân thể để thực hiện phương pháp đoạt xá, qua đó gia tăng tuổi thọ. Kiền Phong cũng được bổ nhiệm làm chỉ huy cuộc chiến chống Tiên Di Tộc trên Chu Tước Tinh, và là một trong bốn người được Vân Tước Tử xếp vào danh sách bồi dưỡng làm Chu Tước Tử kế nhiệm.","nguon":["@c0402","@c0412"],"aliases":["#chu-tuoc-quyet-van-lam"]},{"id":"lay-vat-hoa-than","name":"Lấy vật hóa thân","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Thần thông Anh Biến kỳ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Thần thông của tu sĩ Anh Biến kỳ, dùng một tượng khắc gỗ niệm “Hóa!” để tạo ra phân thân giống hệt bản thể.","detail":"Là thần thông đặc hữu của tu sĩ Anh Biến kỳ. Người thi triển lấy ra một tượng khắc gỗ rồi niệm khẩu quyết “Hóa!”, lập tức tạo ra một phân thân có hình dạng giống hệt bản thể, có thể điều khiển lao đi thay mình th��m dò. Khi Vương Lâm dùng phân thân này lao vào cái cây khổng lồ phòng vệ của hố sâu Tiên Di tộc, phù hào màu đen trong thân cây lóe lên chui vào phân thân, khiến nó lập tức hóa trở lại thành tượng gỗ rơi xuống đất — qua đó hắn xác định thân thể thường rất khó tiến vào cây.","nguon":["@c0403"]},{"id":"khai-giap-hon-phach","name":"Khải giáp hồn phách","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Thuật dùng hơn hai ngàn hồn phách tụ thành bộ khải giáp bao quanh nhục thân để xuyên qua cơ quan vốn chỉ ngăn linh lực.","detail":"Vương Lâm phất Thiên Hồn Phiên, điều hơn hai ngàn hồn phách (bao gồm cả tàn hồn Kỳ Lân thú) bay ra tụ lại thành một bộ khải giáp bao bọc toàn thân nhục thể. Tàn hồn Kỳ Lân áp ở trước ngực phát ra kim mang. Vì cái cây phòng vệ hố sâu Tiên Di tộc chỉ ngăn vật mang linh lực và tượng khắc gỗ chứ không ngăn hồn phách, nhờ lớp khải giáp hồn phách bao thân hắn cảm thấy khí tức lạnh như băng đảo qua người rồi xuyên thẳng được vào bên trong thân cây.","nguon":["@c0403"]},{"id":"nghi-thuc-hut-tinh-huyet-luan-hoi-thu","name":"Nghi thức hút tinh huyết Luân Hồi thụ","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"","hePhai":"Tiên Di tộc","soHuu":[],"blurb":"Trận thuật chú thuật của Tiên Di tộc: các Thuật Chú Sư niệm chú đẩy phù văn vào Luân Hồi thụ, kích cây quấn hút tinh huyết tu sĩ để chữa thương.","detail":"Nghi thức quỷ dị của Tiên Di tộc thực hiện quanh Luân Hồi thụ tầng bốn. Mười một lục diệp Thuật Chú Sư khoanh chân niệm chú ngữ, để phù văn rời thân bay lên không rồi cùng hét lớn, điên cuồng phóng phù văn vào thân Luân Hồi thụ. Cây chấn động, rễ mềm chui lên mặt đất uốn éo như rắn, quấn lấy hơn trăm tu sĩ Kết Đan kỳ (hai mắt mờ mịt) nhấc bổng lên không trung. Phù văn lóe sáng hút cạn tinh hoa huyết nhục và linh lực của các tu sĩ, dung nhập vào cây rồi chuyển hóa thành lực lượng tuôn vào cơ thể bát diệp Thuật Chú Sư trọng thương đang nằm trong khối cầu sáng trên thân cây, giúp y khôi phục thương thế.","nguon":["@c0403"]},{"id":"tran-phap-chong-thien-phu-than-thong-cu-ma","name":"Trận pháp chống thiên phú thần thông Cự Ma tộc","cn":"","loai":"khac","loaiLabel":"Trận pháp / Truyền tống trận","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Trận pháp Vương Lâm từng dùng để chống lại thiên phú thần thông của lão tổ Cự Ma tộc năm xưa, đồng thời tạo thành truyền tống trận nhỏ để ẩn giấu giao động.","detail":"Trận pháp hình thành từ ngọc giản do Độn Thiên đưa, có thể bày ra một truyền tống trận nhỏ rồi đặt vào một mảnh tiên ngọc làm điểm liên kết. Vương Lâm từng dùng trận này để chống lại thiên phú thần thông của lão tổ Cự Ma tộc trong quá khứ. Trận có ưu thế dễ ẩn giấu giao động, thích hợp dùng làm điểm rút lui khi tiến vào hiểm địa. Trước khi nhảy xuống tầng thứ mười một sào huyệt Tiên Di tộc, Vương Lâm đã bày sẵn trận này như đường lui phòng bất trắc.","nguon":["@c0405"]},{"id":"truyen-tong-tran","name":"Truyền Tống Trận","cn":"傳送陣","loai":"khac","loaiLabel":"Trận pháp dịch chuyển","phamCap":"Trận pháp dịch chuyển không gian","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Trận pháp dịch chuyển tức thời, Vương Lâm tự bố trí sẵn để thoát thân khi bị truy bức.","detail":"Một loại trận pháp truyền tống do Vương Lâm tự bố trí từ trước tại tầng thứ mười vùng đất Tiên Di. Khi kích hoạt, người dùng bấm quyết dồn tiên lực vào trận, lập tức được dịch chuyển tức thời sang vị trí khác, dùng để thoát khỏi vòng vây. Vương Lâm đã vờ bay tới cửa rồi bất ngờ kích hoạt trận, dịch chuyển thoát khỏi sự phong tỏa của tam tổ Mị Cơ, rồi tiếp tục bay nhanh tẩu thoát.","nguon":["@c0406"]},{"id":"chu-tuoc-huyen-tran","name":"Chu Tước Huyền Trận","cn":"朱雀玄陣","loai":"khac","loaiLabel":"Trận pháp truyền thừa","phamCap":"Trận pháp lợi hại nhưng con dao hai lưỡi","hePhai":"Chu Tước Sơn","soHuu":["Chu Tước Tử","Kiền Bình Hải","Kiền Phong"],"blurb":"Trận pháp truyền thừa của Chu Tước Sơn, uy lực lớn nhưng là con dao hai lưỡi, mỗi lần dùng đều tổn hại nguyên thần.","detail":"Một trận pháp lợi hại được truyền thừa trong nội bộ Chu Tước Sơn. Đặc tính của nó là con dao hai lưỡi: mỗi lần thi triển đều gây tổn hại nguyên thần người dùng, nếu dùng đủ số lần sẽ làm hỏng nguyên thần vĩnh viễn. Kiền Bình Hải (Chu Tước Tử đời trước) từng truyền cho Chu Tước Tử kế nhiệm. Về sau Chu Tước Tử lại âm thầm truyền lại cho Kiền Phong — hậu nhân của Kiền Bình Hải có linh căn và dáng vẻ giống tổ — như một quân cờ để báo thù trong ván cờ tranh đoạt Tu Tinh Chi Tinh.","nguon":["@c0406"]},{"id":"phong-dong","name":"Phong Động","cn":"風動","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Pháp thuật bậc thấp","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Pháp thuật bậc thấp tạo gió, tu sĩ Trúc Cơ Kỳ cũng nắm bắt được; trong tay Vương Lâm ẩn chứa tiên lực nên uy lực tăng vọt.","detail":"Phong Động là một pháp thuật bậc thấp thông dụng, đến cả tu sĩ Trúc Cơ Kỳ cũng có thể thi triển, vốn chỉ tạo ra luồng gió bình thường. Tuy nhiên khi Vương Lâm thi triển, hắn ngầm dẫn tiên lực vào pháp thuật khiến uy lực mạnh gấp vô số lần: cuồng phong nổi lên thành lốc xoáy lớn cuốn tan cả đám sương trắng âm hàn dày đặc, làm lộ ra thi thể khổng lồ của tổ tiên Cự Ma Tộc bị giam cầm bên trong. Đây là minh chứng cho việc cùng một pháp thuật thấp kém nhưng nguồn lực vận dụng khác nhau thì uy lực chênh lệch trời vực.","nguon":["@c0409"]},{"id":"cam-che-phong-an","name":"Cấm chế phong ấn (Phong)","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật cấm","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Thuật cấm Vương Lâm thúc động cấm phiên, hô “Phong” biến cấm khí thành lưới hắc quang phong ấn mục tiêu.","detail":"Vương Lâm thúc động cấm phiên rồi hô “Phong”, khiến cấm khí biến thành cấm chế hắc quang trải ra như một tấm lưới lớn, phong ấn cái cây màu xanh tím ký sinh trên ngực người khổng lồ Lôi Cát. Cấm chế khống chế cái cây không cho cử động, đồng thời có thể thu hồi trở về cấm phiên khi cần. Khi Vương Lâm gỡ cấm chế thu về cấm phiên, đám cành cây xanh tím lập tức nhúc nhích trở lại.","nguon":["@c0410"]},{"id":"thap-diep-thuat-chu-su","name":"Thập diệp thuật chú sư","cn":"","loai":"khac","loaiLabel":"Cảnh giới Thuật Chú Sư","phamCap":"Thập diệp","hePhai":"Tiên Di Tộc","soHuu":[],"blurb":"Cấp bậc thuật chú sư mười lá của Tiên Di Tộc; hai vị thập diệp từng đuổi giết Lôi Cát khiến hắn trọng thương.","detail":"Thập diệp thuật chú sư là một cấp bậc cao trong hệ thống thuật chú sư của Tiên Di Tộc, biểu thị bằng số lá (diệp). Năm xưa khi Lôi Cát của Cự Ma Tộc đánh nhau với Tiên Di Tộc, hắn bị hai thập diệp thuật chú sư hợp lực đuổi giết; tuy chạy thoát nhưng mang trọng thương, tạo điều kiện để Thi Âm Tông thừa dịp mời tu sĩ đại thần thông bắt và phong ấn hắn.","nguon":["@c0410"]},{"id":"chu-tuoc-an","name":"Chu Tước Ấn","cn":"","loai":"than-thong","loaiLabel":"Thần thông thuật","phamCap":"Thần thông bậc thấp (do tu chân liên minh ban)","hePhai":"Chu Tước Tử / Tu chân liên minh","soHuu":["Diệp Vô Ưu"],"blurb":"Thần thông ấn quyết do tu chân liên minh ban cho Diệp Vô Ưu, uy lực kinh người nhưng tiêu hao tuổi thọ khi dùng.","detail":"Chu Tước Ấn là một thần thông thuật dạng ấn quyết, do tu chân liên minh ban cho đệ nhất Chu Tước Tử Diệp Vô Ưu. Tuy được xếp là thần thông bậc thấp trong các thần thông liên minh ban, nhưng đủ khiến thực lực của Chu Tước Tử tăng lên rất nhiều, đứng trên đỉnh trong đám Vấn Đỉnh tu sĩ. Uy lực kinh người, song khi thi triển sẽ tiêu hao tuổi thọ nên không thể dùng liên tục. Chu Tước Ấn chỉ có thể thi triển sau khi người dùng kế thừa Tu Tinh Chi Tâm. Thần thông thuật do liên minh ban cũng giống tiên bảo, được chia theo cấp bậc.","nguon":["@c0412"]},{"id":"luyen-tien-phan-nguyen","name":"Luyện Tiên Phản Nguyên","cn":"","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Phương pháp tu luyện Anh Biến đặc biệt: rửa sạch phàm căn ngay từ sớm, khiến tu sĩ Anh Biến sơ kỳ mạnh ngang Anh Biến hậu kỳ.","detail":"Luyện Tiên Phản Nguyên là một phương pháp tu luyện cảnh giới Anh Biến hiếm người dám thử nghiệm. Thay vì đi theo con đường thông thường — cô đọng tiến lên Anh Biến rồi đợi đến giữa hậu kỳ mới tẩy rửa phàm căn — phương pháp này chủ trương rửa sạch phàm căn ngay từ sớm. Nhờ vậy, sức mạnh mà nó đem lại vượt trội hơn nhiều so với cách thông thường: một tu sĩ Anh Biến sơ kỳ tu theo phương pháp này có thể mạnh ngang hàng với Anh Biến hậu kỳ, khiến tiên lực gần như xuyên suốt toàn thân chạy theo huyết mạch nên người ngoài khó phân biệt cảnh giới thật. Vì độ khó và rủi ro cao, rất ít người dám đi con đường này. Vương Lâm được người trung niên bí ẩn khen ngợi nghị lực khi dùng phương pháp này để rửa phàm căn.","nguon":["@c0414"]},{"id":"kiem-mang-hinh-vang-trang","name":"Kiếm mang hình vầng trăng","cn":"","loai":"kiem-quyet","loaiLabel":"Kiếm quyết","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Chiêu kiếm Vương Lâm dùng tiên kiếm ngưng tụ thành một đạo kiếm mang như vầng trăng, gào thét phá không lao tới.","detail":"Vương Lâm vận tiên kiếm ngưng tụ một đạo kiếm mang mang hình vầng trăng, gào thét phá không lao tới với uy thế cường đại. Kiếm mang có thể thu nhỏ một nửa để tập trung xuyên phá, đủ sức phá tan khiên khói đen do hỏa linh dựng lên rồi rạch vết trên ngọn lửa xanh. Lần đầu thi triển trong vùng đất khô cằn của Chu Tước Mộ, chiêu này chưa rót tiên lực nên chỉ là đòn thử sức; khi nạp đủ tiên lực thì uy lực còn mạnh hơn nhiều lần.","nguon":["@c0415"]},{"id":"tien-thuc","name":"Tiên thức","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Tiên gia chi thuật","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Thần thức dung nhập tiên lực mà hóa thành, đủ sức phá cấm cố ẩn giấu trong khối đất chứa mệnh hồn.","detail":"Tiên thức là trạng thái cao cấp của thần thức khi Vương Lâm đem thần thức dung nhập vào tiên lực mà luyện hóa thành. Khi thần thức thông thường đảo qua khối đất nhỏ chứa mệnh hồn thì bị một lực lượng kỳ dị ngăn cản, không cách nào dò xét. Sau khi chuyển thành tiên thức, hắn liền phá vỡ được cấm cố trên khối đất, tiến vào bên trong và tách lộ ra mệnh hồn — tia lửa màu xanh ẩn hỏa thuộc tính của một phàm nhân. Tiên thức thể hiện tầng thứ vượt xa thần thức tu sĩ phàm tục, gắn liền với tiên lực mà Vương Lâm sở hữu.","nguon":["@c0416"]},{"id":"nhat-kiem-trung-thien","name":"Nhất kiếm trùng thiên","cn":"","loai":"kiem-quyet","loaiLabel":"Kiếm thuật","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Kiếm thuật của Vương Lâm: một kiếm ẩn chứa tiên lực bùng như tia chớp, sáng tựa cầu vồng, mang khí lãng cuồn cuộn xông tới.","detail":"Là chiêu kiếm Vương Lâm dùng đối phó Liễu Mi tại thung lũng Tế Đàn trong Chu Tước Mộ. Khi thúc tiên lực vào kiếm tiên, một kiếm này phát ra ánh sáng chói lọi, ẩn chứa tiên lực tựa tia chớp, rạng rỡ như cầu vồng, đồng thời mang theo khí lãng to lớn gào rít quét tới đối thủ. Trước uy lực ấy, Liễu Mi phải triệu hư ảnh Khổng Tước, dùng lông chim diễm lệ mới chống đỡ được kiếm quang.","nguon":["@c0418"]},{"id":"hu-anh-khong-tuoc","name":"Hư ảnh Khổng Tước","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Chu Tước Tử (môn hạ)","soHuu":["Liễu Mi"],"blurb":"Thần thông phòng ngự của Liễu Mi: bấm quyết triệu hư ảnh Khổng Tước, phóng lông chim diễm lệ đỡ kiếm quang.","detail":"Khi đối đầu Vương Lâm, Liễu Mi bấm quyết triệu xuất một hư ảnh Khổng Tước, hai mắt loé lên lục mang. Hư ảnh phóng ra hơn mười chiếc lông chim diễm lệ giăng thành tầng phòng ngự, đón đỡ kiếm quang của Nhất kiếm trùng thiên. Đây là thủ đoạn nghênh chiến đầu tiên Liễu Mi dùng để hoá giải sát chiêu của Vương Lâm trong thung lũng Tế Đàn ở Chu Tước Mộ.","nguon":["@c0418"]},{"id":"hoa-truc-sinh-tu-luan-hoi","name":"Hoạ trục sinh tử luân hồi","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Bí thuật của Vương Lâm: bấm quyết điểm mi tâm triệu một Hoạ trục cực lớn từ bụi khí, hiện tranh thuỷ mạc đen trắng và đánh ra Thanh Long, mang ý cảnh sống chết luân hồi.","detail":"Hoạ trục sinh tử luân hồi là một thần thông kiêm ý cảnh do Vương Lâm thi triển. Hắn bấm quyết điểm vào mi tâm, từ bụi khí xung quanh triệu hồi một Hoạ trục cực lớn, phát ra lực lượng kỳ dị bao phủ bốn phía. Hoạ trục hiện ra tranh thuỷ mạc đen trắng với cảnh nước từ núi chảy xuống, rồi tuôn bụi khí hoá thành một con Thanh Long lớn lao tới ngoạm đối thủ. Thanh Long khi va chạm tan thành bụi khí bao phủ, mang theo ý cảnh về sống và chết, tồn tại và tan biến, luân hồi không ngừng. Trong trận đấu ý cảnh với Liễu Mi, ánh sáng và màu sắc của hai bên dung hợp với tranh thuỷ mạc, khiến bức tranh dần có thêm màu. Ý cảnh này gắn với suy ngẫm của Vương Lâm về sự sống chết và ký ức tình cảm của hắn.","nguon":["@c0419"]},{"id":"thien-huyen-vo-tinh","name":"Thiên huyễn vô tình","cn":"","loai":"cong-phap","loaiLabel":"Đạo / Ý cảnh","phamCap":"","hePhai":"","soHuu":["Liễu Mi"],"blurb":"Đạo của Liễu Mi, biểu hiện qua hơn một ngàn lông đuôi Khổng Tước; mỗi lông là một huyễn (thực chất 999 huyễn), khi huyễn cuối hình thành thì ý cảnh đạt Anh Biến hậu kỳ.","detail":"Thiên huyễn vô tình là đạo mà Liễu Mi tu luyện, lấy cốt lõi là sự vô tình lạnh lùng bẩm sinh. Khi vận đạo, Liễu Mi khoanh chân ngồi nhắm mắt, Khổng Tước bay lên bành trướng cao hơn mười trượng, đuôi xoè che kín thung lũng. Mỗi lông đuôi của Khổng Tước là một huyễn; nàng tuyên bố có hơn một ngàn nhưng thực chất là 999 huyễn. Khi huyễn thứ một ngàn (cuối cùng) hình thành, ý cảnh của nàng sẽ đạt cảnh giới Anh Biến hậu kỳ. Đuôi Khổng Tước bảy màu (đỏ, xanh, vàng, lục, lam, chàm, tím) phát ra ý cảnh vô tình băng hàn, khiến sương lạnh thêm lạnh, bốn mùa đột biến. Sự vô tình bẩm sinh của Liễu Mi được Vương Lâm đánh giá cao hơn một bậc so với tuyệt tình, vì vô tình không cần đoạn tuyệt mà vốn dĩ đã không có tình.","nguon":["@c0419"]},{"id":"khong-tuoc-xoe-duoi","name":"Khổng Tước xoè đuôi","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Liễu Mi"],"blurb":"Thần thông của Liễu Mi: triệu hư ảnh Khổng Tước, quát Khai cho xoè hết lông, phát tiên lực cuồn cuộn hoá tiên khí trắng tràn ngập, đuôi bảy màu phát ý cảnh vô tình.","detail":"Khổng Tước xoè đuôi là thần thông Liễu Mi dùng trong trận chiến với Vương Lâm. Nàng điểm tay triệu ra hư ảnh Khổng Tước trên đầu mình, rồi quát Khai, Khổng Tước xoè hết lông khiến cả thung lũng sáng ngời. Một cỗ tiên lực cuồn cuộn hoá thành tiên khí trắng tràn ngập, đủ sức đánh khiến thân Vương Lâm dừng lại. Khi vận đạo Thiên huyễn vô tình, Khổng Tước bay lên bành trướng cao hơn mười trượng, đuôi xoè che kín thung lũng; đuôi mang bảy màu (đỏ, xanh, vàng, lục, lam, chàm, tím) phát ra ý cảnh vô tình băng hàn. Khổng Tước cũng từng hứng đòn trường thương tím vàng của Vương Lâm, sau hai lần va chạm thì ảm đạm đi và khiến sắc mặt Liễu Mi hơi tái.","nguon":["@c0419"]},{"id":"vo-tinh-dao","name":"Vô tình đạo","cn":"","loai":"cong-phap","loaiLabel":"Ý cảnh","phamCap":"Ý cảnh","hePhai":"","soHuu":["Liễu Mi"],"blurb":"Đạo tâm vô tình của Liễu Mi, bị ý cảnh chí âm chí dâm khắc chế.","detail":"Vô tình đạo là đạo tâm tu luyện của Liễu Mi, nền tảng để ngưng tu thành Thiên huyễn. Muốn phá vô tình đạo cần một ý cảnh chí âm chí dâm: lấy dâm dục gợi tình dục để bài trừ vô tình. Vương Lâm nắm được nguyên lý này sau khi xem ngọc giản của Chu Vũ Thái, từ đó dùng ý cảnh Mị Cơ làm sát chiêu khắc chế Liễu Mi.","nguon":["@c0420"]},{"id":"thien-huyen-huyen","name":"Thiên huyễn / huyễn","cn":"","loai":"khac","loaiLabel":"Cảnh giới ý cảnh","phamCap":"Cảnh giới ý cảnh","hePhai":"","soHuu":["Liễu Mi"],"blurb":"Cảnh giới ý cảnh của Liễu Mi: tu đủ một nghìn ‘huyễn’ thì thành Thiên huyễn.","detail":"Thiên huyễn là cảnh giới ý cảnh tối cao mà Liễu Mi theo đuổi. Để đạt tới, người tu cần tu thành đủ một nghìn ‘huyễn’. Vào thời điểm đối đầu Vương Lâm, Liễu Mi tuyên bố đã tu được chín trăm chín mươi chín ‘huyễn’, chỉ còn thiếu một ‘huyễn’ cuối cùng là tu thành Thiên huyễn — vì thế cô ta khăng khăng ép Vương Lâm để hoàn thành ‘huyễn’ cuối.","nguon":["@c0420"]},{"id":"phu-van-hien-te-dau-lau-hu-to","name":"Phù văn hiến tế (đầu lâu Hư tổ)","cn":"","loai":"bi-thuat","loaiLabel":"Chú thuật / Trận pháp","phamCap":"Thần lực","hePhai":"Tiên Di Tộc","soHuu":["Nhất tổ (Tiên Di Tộc)","Tam tổ (Tiên Di Tộc)","Vân Tiên Tử"],"blurb":"Phù văn chứa thần lực khắc trên đầu lâu Hư tổ; nhiều người Tiên Di Tộc đồng thời hiến tế để đưa một người vào Chu Tước Mộ.","detail":"Đầu lâu Hư tổ khắc phù văn cao thâm vượt xa loại phù văn Vương Lâm có vô số lần, được Phù văn Tinh viễn Cổ Thần linh chỉ điểm nên đã chứa thần lực và ngưng tụ khí tức cường đại. Nghi thức hiến tế cần Nhất tổ, Tam tổ, Vân Tiên Tử cùng hai mươi Diệp tổ linh khoanh chân ngồi quanh đầu lâu, mi tâm loé thực vật bản mạng tản quang yêu dị; nếu đồng thời hiến tế thì có thể đưa được một người của Tiên Di Tộc vào Chu Tước Mộ.","nguon":["@c0420"]},{"id":"thien-huyen-tinh-duc-dao","name":"Thiên Huyễn Tình Dục Đạo","cn":"","loai":"cong-phap","loaiLabel":"Đạo / Công pháp tu luyện","phamCap":"Anh Biến trung kỳ","hePhai":"Liễu Mi","soHuu":["Liễu Mi"],"blurb":"Dạng biến dị của Thiên Huyễn Vô Tình Đạo khi ‘huyễn’ cuối cùng dung hợp Mị Cơ, ý cảnh chuyển từ vô tình sang dục ý.","detail":"Khi ‘huyễn’ cuối cùng của Liễu Mi dung hợp tia dâm tà ý cảnh của Mị Cơ, Thiên Huyễn Vô Tình Đạo biến chất thành Thiên Huyễn Tình Dục Đạo. Ý cảnh từ tuyệt tình vô tình chuyển sang dục ý, sinh ra bụi phấn dục ý lan tràn mấy vạn dặm, biến cả vùng thành thế giới màu hồng. Đây là kết quả ngoài dự tính của Liễu Mi, khiến tâm tư nàng phức tạp mờ mịt vì trong ‘huyễn’ cuối có hơi thở của ‘sư phụ’ liên hệ tới Vương Lâm.","nguon":["@c0421"]},{"id":"van-dinh-trieu-van-dao","name":"Vấn Đỉnh Triêu Văn đạo","cn":"","loai":"cong-phap","loaiLabel":"Pháp môn cảm ngộ","phamCap":"Vấn Đỉnh kỳ","hePhai":"Tu Chân Liên Minh","soHuu":[],"blurb":"Con đường mà tu sĩ Vấn Đỉnh phải thông qua để có cơ hội rút mệnh hồn từ Tu Tinh Tinh.","detail":"Vấn Đỉnh Triêu Văn đạo là pháp môn cảm ngộ dành cho tu sĩ đạt cảnh giới Vấn Đỉnh. Chỉ khi thông qua con đường này, trong cảm ngộ trạng thái Tịch Tử Hĩ, tu sĩ mới có cơ hội rút được mệnh hồn của mình từ Tu Tinh Tinh. Tuy nhiên tỷ lệ thành công của Vấn Đỉnh kỳ chỉ vào khoảng một nửa; muốn rút mệnh hồn rời tu chân tinh mà không bị cản trở thì phải đạt cảnh giới trên Vấn Đỉnh hoặc quốc gia thăng từ Ngũ cấp lên Lục cấp.","nguon":["@c0422"]},{"id":"tich-tu-hi","name":"Tịch Tử Hĩ","cn":"","loai":"cong-phap","loaiLabel":"Trạng thái cảm ngộ","phamCap":"Vấn Đỉnh kỳ","hePhai":"Tu Chân Liên Minh","soHuu":[],"blurb":"Cảnh ngộ cảm ngộ cần thiết, đi kèm Vấn Đỉnh Triêu Văn đạo để rút mệnh hồn từ Tu Tinh Tinh.","detail":"Tịch Tử Hĩ là một trạng thái cảm ngộ mà tu sĩ Vấn Đỉnh phải đạt tới trong quá trình đi theo Vấn Đỉnh Triêu Văn đạo. Chỉ khi cảm ngộ được Tịch Tử Hĩ, tu sĩ mới có cơ hội rút mệnh hồn từ Tu Tinh Tinh. Đây là một trong những điều kiện cốt lõi quyết định khả năng đoạt lại mệnh hồn của mình.","nguon":["@c0422"]},{"id":"phan-nguyen-than-phong-an","name":"Phân nguyên thần phong ấn","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Thần thông phân nguyên thần thành vô số phần, mỗi phần chui vào một mệnh hồn rồi hô phong ấn.","detail":"Vương Lâm đặt tay lên mi tâm, nguyên thần loé lên từ đỉnh đầu lao ra hoá thành thần niệm cao mười trượng. Khi kiếm tiên xuyên ngực nữ tử thuỷ mệnh hồn khiến nàng tản thành vô số giọt nước, nguyên thần Vương Lâm phân thân từ một thành hai, bốn, tám rồi vô số, mỗi phần chui vào một mệnh hồn rồi hô ‘Phong!’ — cấm chỉ phong ấn toàn bộ giọt nước. Xong việc nguyên thần trở về thân thể.","nguon":["@c0423"]},{"id":"ton-hon-phien-dung-hop","name":"Tôn Hồn Phiên dung hợp","cn":"","loai":"than-thong","loaiLabel":"Thần thông pháp bảo","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Thần thông của Thập Ức Tôn Hồn Phiên dung hợp vô số hồn phách vào Chủ Hồn để tạo ra Chủ Hồn mạnh hơn.","detail":"Vương Lâm niệm ‘Tôn Hồn Phiên, dung!’ — vô số hồn phách dung hợp vào Chủ Hồn. Sau khi gom lại còn sáu con Chủ Hồn với khí tức vượt qua Anh Biến kỳ nhưng chưa tới Vấn Đỉnh kỳ. Sáu Chủ Hồn này vây nữ tử thuỷ mệnh hồn rồi thi triển thần thông, ép nàng hoá thành hơi nước tản ra bốn phía.","nguon":["@c0423"]},{"id":"hoan-hon-thuat","name":"Hoán Hồn Thuật","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Cổ Thần thuật","hePhai":"Cổ Thần tộc","soHuu":["Thác Lâm"],"blurb":"Cổ Thần thuật của Thác Lâm, dùng để rời khỏi nơi bị phong ấn khi xuất hiện kẽ hở.","detail":"Hoán Hồn Thuật là một Cổ Thần thuật do Thác Lâm nắm giữ. Nhờ cỗ lực lượng Tu Chân Tinh trưởng thành trong tinh cầu khiến phong ấn xuất hiện kẽ hở, Thác Lâm có thể vận dụng Hoán Hồn Thuật để thoát khỏi cảnh giam cầm trong Cổ Thần chi địa. Đây là mấu chốt trong kế hoạch thoát khốn của hắn.","nguon":["@c0424"]},{"id":"co-than-hien-te","name":"Cổ Thần Hiến tế","cn":"","loai":"khac","loaiLabel":"Nghi thức / Thần thông","phamCap":"","hePhai":"Cổ Thần tộc","soHuu":["Đồ Ti","Tiên Di Tộc"],"blurb":"Các chỗ hiến tế do Đồ Ti dựng cho dân bản xứ; nơi còn giữ thì Cổ Thần thi triển được chút thần thông.","detail":"Cổ Thần Hiến tế là những nơi hiến tế được Đồ Ti xây dựng năm xưa khi đặt phân thân tại đây, được dân bản xứ tôn sùng như thần linh. Sau hàng vạn năm dân bản xứ chết sạch, chỉ còn Tiên Di Tộc ẩn dật giữ lại một chỗ Cổ Thần Hiến tế cuối cùng. Tại nơi còn giữ hiến tế, Cổ Thần như Thác Lâm vẫn còn thi triển được chút thần thông dù đang bị phong ấn.","nguon":["@c0424"]},{"id":"co-quai-phong","name":"Cổ quái phong","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Thần thông Vương Lâm bấm quyết niệm chú phóng ra một cổ quái phong ẩn chứa tiên lực, cuốn lấy khí lãng địch và phản công.","detail":"Cổ quái phong là thần thông Vương Lâm thi triển bằng cách bấm quyết niệm chú, phóng ra một cổ quái phong ẩn chứa tiên lực. Khi Côn Cực Tiên của Hồng Điệp va vào trường thương gây khí lãng kinh thiên, Vương Lâm đứng yên để cổ quái phong cuốn lấy khí lãng và dội ngược về phía Hồng Điệp. Quái phong vừa thủ vừa công, song vẫn bị Côn Cực Tiên hoá tia chớp đen xuyên thủng.","nguon":["@c0427"]},{"id":"hoa-hong-than-thuc","name":"Hoa hồng thần thức","cn":"","loai":"than-thong","loaiLabel":"Thuật thần thức","phamCap":"","hePhai":"","soHuu":["Hồng Điệp"],"blurb":"Thuật của Hồng Điệp: phun hồng quang hoá thành đoá hoa hồng trong suốt màu đỏ, nhuỵ hoa tản khói hồng che giấu tia thần thức thật.","detail":"Hoa hồng thần thức là thuật Hồng Điệp dùng để giấu kỹ tia thần thức thật của mình. Nàng phun ra hồng quang hoá thành một đoá hoa hồng trong suốt màu đỏ; nhuỵ hoa phiêu tán làn khói hồng, trong đó hiện lên hình bóng Hồng Điệp ngạo ý — giống hệt Hồng Điệp trong lòng Vương Lâm. Đây mới chính là tia thần thức thật được nàng che giấu, qua đó nàng kiêu ngạo cầu Vương Lâm ra tay giết mình.","nguon":["@c0427"]},{"id":"thu-an-an-cua-tien-luc","name":"Thủ ấn ấn cửa (tiên lực)","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Vấn Đỉnh","hePhai":"","soHuu":["Vân Tước Tử"],"blurb":"Đạo tiên lực mạnh mẽ hóa thành thủ ấn thật lớn ấn vào cửa Mộ.","detail":"Vân Tước Tử vung tay phải, một đạo tiên lực mạnh mẽ phun ra hóa thành thủ ấn thật lớn ấn vào cánh cửa lớn của Chu Tước Mộ trên đỉnh Linh Sơn. Cửa chấn động ầm ầm nhưng không tăng thêm vết nứt, còn thủ ấn thì bị nuốt vào bên trong, trống rỗng biến mất. Lão dùng thủ ấn này để thử mở cửa Mộ nhưng thất bại, đành nhíu mày chờ lần sụp đổ tiếp theo.","nguon":["@c0429"]},{"id":"ban-mang-thuat","name":"Bản mạng thuật","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Cổ Thần Đồ Ti","soHuu":["Thác Lâm"],"blurb":"Thần thông bẩm sinh Thác Lâm nắm giữ khi sinh ra từ ma niệm Đồ Ti, qua đó vận dụng được chút lực lượng truyền thừa.","detail":"Bản mạng thuật là các thần thông tự nhiên nắm giữ ngay khi sinh ra của ma niệm Thác Lâm — vốn sinh từ Cổ Thần Đồ Ti. Tuy Thác Lâm thừa kế toàn bộ lực lượng truyền thừa bát tinh Cổ Thần, hắn không thể thi triển trọn vẹn, chỉ thông qua các bản mạng thuật mà phát huy được chút lực lượng ở cấp thấp nhất, tương đương khoảng năm tinh Cổ Thần. Dù vậy mức ấy vẫn siêu việt Vấn Đỉnh kỳ.","nguon":["@c0430"]},{"id":"luc-duc-thien-ma-quyet","name":"Lục Dục Thiên Ma quyết","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"","hePhai":"Lục Dục Ma quân","soHuu":["Lục Dục Ma quân","Lão già âm trầm"],"blurb":"Pháp thuật ma công thành danh năm xưa của Lục Dục Ma quân, có thể ép đối thủ tự bạo thể.","detail":"Là pháp thuật thành danh năm xưa của Lục Dục Ma quân. Người thi triển điểm tay liên tục, lần lượt niệm các ý dục “Tham, si…” khiến đối tượng thân run lên, mắt loé yêu mang, hai đạo quang mang điên cuồng phát ra. Khi niệm tới chữ “Bạo!” thì đối tượng tự bạo thể, khí lãng cuồn cuộn bùng ra. Lão già âm trầm dùng pháp thuật này điều khiển hai người Tiên Di Tộc, ép họ tự bạo phá cánh cửa giữa không trung trong Chu Tước Mộ.","nguon":["@c0431"]},{"id":"luc-cam-thuan-di-long-bien","name":"Lực cấm thuấn di trong lòng biển","cn":"","loai":"bi-thuat","loaiLabel":"Cấm chế","phamCap":"","hePhai":"Cung điện dưới lòng biển","soHuu":[],"blurb":"Luồng lực kỳ dị bao phủ lòng biển, hạn chế mọi pháp thuật thuấn di.","detail":"Một loại lực lượng kỳ dị bao trùm khắp lòng biển nơi tọa lạc cung điện dưới đáy biển, có tác dụng cấm chế — khiến tu sĩ không thể vận dụng pháp thuật thuấn di để di chuyển nhanh. Vương Lâm khi tiến vào liền nhận ra ngay đặc tính này mà không cần thử nghiệm, nên buộc phải dựa vào tốc độ bay và pháp bảo để vượt qua cửa ải kiếm quang. Cấm chế này có thể ảnh hưởng tới cách di chuyển và chiến đấu của tu sĩ trong và sau cung điện.","nguon":["@c0432"]},{"id":"tran-phap-vay-khon-van-tuoc-tu","name":"Trận pháp vây khốn của Vân Tước Tử","cn":"","loai":"bi-thuat","loaiLabel":"Trận pháp","phamCap":"","hePhai":"","soHuu":["Vân Tước Tử"],"blurb":"Trận pháp Vân Tước Tử dùng để vây khốn lão già Âm Sâm trong cung điện dưới đáy biển, song chỉ giữ được trong thời gian ngắn.","detail":"Vân Tước Tử bố trí trận pháp này để vây khốn lão già Âm Sâm — đối thủ mang theo một con khỉ, không phải người Chu Tước Tinh, pháp thuật quỷ dị. Vân Tước Tử tự nhận thi triển trận khiến bản thân trọng thương, nhưng trận chỉ giữ được đối thủ trong thời gian ngắn; một khi lão già thoát vây sẽ tranh đoạt bảo vật. Đây là cái cớ Vân Tước Tử dùng để dụ Vương Lâm mang Tu Tinh Chi Tinh đi.","nguon":["@c0433"]},{"id":"anh-cam","name":"Ảnh cấm","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Pháp thuật cực hiếm thời thượng cổ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Pháp thuật cực hiếm thời thượng cổ, lợi dụng lực tàn dư của người đã chết cộng tu vi hóa thành cấm chế giam cầm đối thủ.","detail":"Ảnh cấm là pháp thuật cực kỳ hiếm có từ thời thượng cổ mà Vương Lâm nắm giữ. Cách thi triển là lợi dụng lực tàn dư còn sót lại của người đã chết, cộng thêm tu vi của bản thân, hóa thành cấm chế để giam cầm đối thủ. Khi Vương Lâm bày phù văn vàng giam cầm lão già âm trầm (bị Thác Sâm đoạt xá), lão già nói rõ giới hạn của nó: nếu là chủ nhân bản thể đích thân giáng lâm thì chỉ một quyền là phá vỡ được, nhưng vì kẻ bị vây chỉ là một tia phân thần đoạt xá nên sức bị hạn chế, không thoát ra nổi mà bị cấm chế vây khốn.","nguon":["@c0434"]},{"id":"chu-tuoc-an-truyen-thua","name":"Chu Tước Ấn (thần thông truyền thừa)","cn":"朱雀印","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Thần thông pháp thuật bậc thấp loại truyền thừa","hePhai":"Chu Tước Quốc · Tiên Ấn Phủ","soHuu":["Diệp Vô Ưu","Vương Lâm"],"blurb":"Thần thông pháp thuật bậc thấp thuộc loại truyền thừa, cần tu sĩ phong hào mới thi triển; lưu truyền tại Tiên Ấn Phủ ở Chu Tước Quốc.","detail":"Chu Tước Ấn là thần thông pháp thuật bậc thấp thuộc loại truyền thừa, được thanh âm uy nghiêm trong hư vô tại Tiên Ấn Phủ giảng giải: chỉ tu sĩ mang phong hào mới có thể thi triển. Ấn quyết là một đoạn hồng quang phức tạp dung nhập mi tâm người nhận (như trong ký ức Diệp Vô Ưu), gây cảm giác hồn phách bị khắc, đau đớn tột cùng. Người nhận được tốc độ và lực lượng phi thường — dưới chân xuất hiện hồng quang khuếch tán làm tốc độ tăng vọt, khí tức Chu Tước tràn ngập. Dù tu vi chỉ Anh Biến sơ kỳ, người mang ấn vẫn có thể đánh ngang Vấn Đỉnh. Phù văn của ấn hơi giống phù văn trên đầu lâu Tiên Di Tộc nhưng khác biệt. Vương Lâm vô tình trải nghiệm truyền thừa này qua Tu Tinh Chi Tinh nhưng từ chối trở thành Chu Tước phong hào, khiến ấn quyết rút lui như thủy triều, ngưng tụ lại thành tinh thạch trắng trên tay phải.","nguon":["@c0435"]},{"id":"hoa-than-chi-menh-chu-tuoc-tu","name":"Hóa thân chi mệnh (pháp thuật đoạt thọ nguyên Chu Tước Tử)","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Pháp thuật bí truyền nhiều đời","hePhai":"Dòng Chu Tước Tử","soHuu":["Chu Tước Tử"],"blurb":"Pháp thuật bí truyền nhiều đời Chu Tước Tử bí mật nghiên cứu nhằm né luân hồi thiên đạo, đoạt xá kéo dài thọ nguyên.","detail":"Hóa thân chi mệnh là pháp thuật bí truyền được nhiều đời Chu Tước Tử nghiên cứu nhằm né tránh luân hồi thiên đạo, thông qua đoạt xá để kéo dài thọ nguyên. Tỷ lệ thành công chưa tới một thành; ngay cả khi thành cũng chỉ tăng thêm mấy mươi năm thọ nguyên mà phải trả giá rất lớn. Pháp thuật dựa trên biến hóa của Tu Tinh Chi Tinh và lấy Đồng nhân làm vật mấu chốt. Chu Tước Tử từ lâu mưu đoạt xá Kiền Phong: từ nhỏ đã khiến Kiền Phong thôn phệ ý cảnh và thể ngộ thiên đạo của người đời trước để chuẩn bị. Khi thi triển, Đồng nhân hút tiên huyết và thọ nguyên/pháp lực qua thất khiếu của Kiền Phong, dung hóa thành đồng lỏng để Chu Tước Tử ngưng hóa lại hình hài. Hình hài hóa thân hiện tại còn nhiều sơ hở trí mạng, ví như cung mạnh đã hết đà.","nguon":["@c0435"]},{"id":"chu-hon-tu-bao","name":"Chủ hồn tự bạo","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Thủ đoạn hồn phách của Vương Lâm: cho một chủ hồn tự bạo, khí tức ngập trời khuếch tán để phá giam cầm và thoát đòn.","detail":"Một thủ đoạn xuất phát từ Thập Ức Tôn Hồn Phiên. Khi Vương Lâm bị khối gỗ xanh của Kiền Phong giam cầm, hắn bình tĩnh cho một chủ hồn tự bạo; khí tức ngập trời từ vụ tự bạo khuếch tán ra, phá vỡ cỗ lực kỳ dị đang trói buộc và giúp hắn né được đao ảnh xanh chém tới đầu. Đây là cách dùng tiêu hao một chủ hồn để đổi lấy sự thoát hiểm tức thời.","nguon":["@c0436"]},{"id":"chu-tuoc-huyen-tran-kien-phong","name":"Chu Tước Huyền Trận (phòng hộ Kiền Phong)","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"","hePhai":"Chu Tước","soHuu":["Kiền Phong"],"blurb":"Trận pháp phòng hộ tự động trên người Kiền Phong, mở ra để ngăn đòn đánh nhưng bị Thác Sâm một trảo phá vỡ vụn.","detail":"Là trận pháp phòng hộ tự động vận hành trên người Kiền Phong. Khi Thác Sâm hư ảnh đỏ xông tới, trận chực ngăn cản nhưng chỉ một trảo của Thác Sâm đã phá vỡ vụn, khiến Kiền Phong càng thêm trọng thương rồi bị đoạt mất thiết kiếm.","nguon":["@c0437"]},{"id":"phap-quyet-toai-diet","name":"Pháp quyết toái diệt","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Tuyệt kỹ liều mạng","hePhai":"Thập Ức Tôn Hồn Phiên","soHuu":["Vương Lâm"],"blurb":"Linh hồn Vấn Đỉnh kết ấn quyết rồi cho toàn bộ linh hồn trong Thập Ức Tôn Hồn Phiên tự bạo, sóng đen dồn thẳng vào một mục tiêu với uy lực hủy thiên diệt địa.","detail":"Đây là đòn toái diệt cuối cùng mà Vương Lâm dùng khi đối đầu phân thức hư ảnh của Thác Sâm. Trước cảm giác tử vong, hắn cho linh hồn Vấn Đỉnh kết ấn quyết, dung nhập thành hắc mang rồi hô ‘Vỡ!’. Lập tức tất cả hàng ức linh hồn trong Thập Ức Tôn Hồn Phiên tự bạo, hóa thành sóng đen có linh tính dồn thẳng về phía Thác Sâm. Tiếng nổ hủy thiên diệt địa làm rúng động cả Chu Tước tinh, khiến Tiểu Hầu bên trong cơ thể Thác Sâm tắt thở, song hư ảnh hồng mang của Thác Sâm vẫn ngưng tụ lại. Cái giá của đòn này là Thập Ức Tôn Hồn Phiên bị hủy và Vương Lâm chỉ còn tu vi Anh Biến sơ kỳ.","nguon":["@c0438"]},{"id":"phong-an-xich-sat-ngu-an","name":"Phong ấn xích sắt ngũ ấn","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Thần thông Sứ Giả","hePhai":"Tu Chân Liên Minh","soHuu":["Mặc Trí"],"blurb":"Năm đạo xích sắt hóa thành năm ấn ký khổng lồ chồng lên nhau, xuyên hư không in lên đối phương để phong ấn — chỉ hiệu quả khi đối phương đã bị thương.","detail":"Thần thông mà Mặc Trí (Sứ Giả Tu Chân Liên Minh) dùng để xử lý phân thức Thác Sâm. Từ mặt biển phóng ra, hắn hô ‘Phong!’ rồi thả năm xích sắt; năm xích sắt này biến thành năm ấn ký khổng lồ chồng lên nhau, xuyên qua hư không in thẳng lên lưng Thác Sâm. Vì Thác Sâm khi ấy đã bị thương bởi linh hồn Vấn Đỉnh tự bạo, ấn ký phát huy tác dụng khiến phân thức của hắn tiêu tán. Đòn này lợi dụng đúng thời điểm đối thủ suy yếu mới có thể trấn áp.","nguon":["@c0438"]},{"id":"dung-hop-linh-hon-van-dinh","name":"Dung hợp linh hồn Vấn Đỉnh","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Thần thông pháp bảo","hePhai":"Thập Ức Tôn Hồn Phiên","soHuu":["Vương Lâm"],"blurb":"Hô ‘Dung!’ để toàn bộ hồn phách trong Thập Ức Tôn Hồn Phiên dung hợp thành một linh hồn tu vi Vấn Đỉnh sơ kỳ, ngưng thực cơ thể và dùng trường thương tử sắc.","detail":"Khả năng đặc biệt của Thập Ức Tôn Hồn Phiên. Khi bị Thác Sâm truy sát, Vương Lâm rung phiên hô ‘Dung!’, toàn bộ hồn phách dung hợp thành một linh hồn Vấn Đỉnh sơ kỳ phát ra tử quang, ngưng thực cơ thể và rút trường thương tử sắc. Mục đích thật không phải giao chiến chính diện mà là mượn tốc độ của cảnh giới Vấn Đỉnh để kẹp Vương Lâm chạy trốn. Tuy nhiên Thác Sâm dùng vòng xoáy hấp lực kéo cả hai quay lại, khiến mưu đồ bất thành.","nguon":["@c0438"]},{"id":"van-huyen-thien-ma-dao","name":"Vạn Huyễn Thiên Ma đạo","cn":"","loai":"cong-phap","loaiLabel":"Đạo pháp / Tâm pháp","phamCap":"Chưa rõ","hePhai":"","soHuu":["Liễu Mi"],"blurb":"Con đường tu hành mới Liễu Mi quyết chuyển sang sau Thiên Huyễn Vô Tình Đạo, để Vương Lâm không nhận ra nàng. (+) Đạo Liễu Mi tu, lấy mê ảo thế gian vạn vật làm cốt lõi; bước thứ hai sẽ sinh thần thông chưa rõ. [CAN-SOAT-GOP]","detail":"Sau khi rời Chu Tước tinh, Liễu Mi sắc mặt khó coi lập thề chuyển đạo. Nàng tự nhủ ngày sau gặp lại Vương Lâm sẽ khác, hắn sẽ không nhận ra nàng nữa: sau Thiên Huyễn Vô Tình Đạo sẽ là Vạn Huyễn Thiên Ma đạo. Đây là tuyến đạo pháp mới gắn với quyết tâm báo thù của Liễu Mi, gợi nàng tái xuất với diện mạo và cảnh giới khác.","nguon":["@c0439","@c0631"]},{"id":"khon-phong-chu","name":"Khốn Phong Chú","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật phòng vệ","phamCap":"","hePhai":"Phường thị tự do","soHuu":["Trương Hóa Lâm"],"blurb":"Pháp thuật phòng vệ buôn bán, vầng sáng mỏng bao phủ vật phẩm, trừ bỏ cần hơn mười lần hít thở trừ khi tu vi cao hơn nhiều.","detail":"Pháp thuật bắt buộc học để buôn bán ở phường thị tự do, tạo vầng sáng mỏng bao phủ vật phẩm nhằm chống cướp đoạt. Người muốn trừ bỏ cần hơn mười lần hít thở, đủ thời gian để người bán thu hồi vật, trừ khi tu vi cao hơn người làm phép rất nhiều. Vương Lâm vung tay phá vỡ Khốn Phong Chú trong nháy mắt, khiến lão Trương kinh hãi đoán tu vi hắn ít nhất Anh Biến kỳ.","nguon":["@c0446"]},{"id":"tinh-chuyen","name":"Tinh Chuyển","cn":"","loai":"than-thong","loaiLabel":"Pháp thuật thần thông","phamCap":"","hePhai":"","soHuu":["Tư Đồ Nam","Vương Lâm"],"blurb":"Pháp thuật của Tư Đồ Nam: ng��ng tụ tiên lực trên đầu ngón tay vẽ vòng tròn xuyên qua mục tiêu, làm chệch hoặc khựng quỹ đạo đòn tấn công.","detail":"Pháp thuật do Tư Đồ Nam truyền cho Vương Lâm. Tiên lực ngưng tụ trên đầu ngón tay vẽ thành đường cong rồi xoay chuyển thành vòng tròn hoàn chỉnh xuyên qua mục tiêu, làm chệch hoặc khựng quỹ đạo của vật/đòn tấn công. Vương Lâm dùng Tinh Chuyển hóa giải chén trà chứa tiên lực khổng lồ của Bạch Vi, khiến chén trà khựng lại rồi xoay vòng quanh hắn.","nguon":["@c0446"]},{"id":"phuong-phap-luyen-khi-co-than","name":"Phương pháp luyện khí kế thừa từ cổ thần","cn":"","loai":"luyen-the","loaiLabel":"Phương pháp luyện khí","phamCap":"Cổ thần","hePhai":"Cổ Thần tộc","soHuu":["Vương Lâm"],"blurb":"Phương pháp tế luyện bảo vật của cổ thần mà Vương Lâm kế thừa, mỗi lần luyện chế thường kéo dài hàng trăm năm.","detail":"Phương pháp tế luyện pháp bảo theo lối cổ thần: dung hợp chậm rãi linh vật và linh dịch vào bảo vật, mỗi lần luyện chế thường kéo dài cả trăm năm; với cửu tinh cổ thần thì ngàn năm luyện bảo cũng chỉ như nháy mắt. Vương Lâm dùng cách này tế luyện lại Tinh La Bàn bằng Khôn Mộc Thạch và Mặc Tuyết Dịch, nhưng vì gấp rút nên bỏ qua quá trình dung hợp chậm, cho thêm Mặc Tuyết Dịch tiến hành tế luyện cuối cùng để rút ngắn còn hơn nửa năm.","nguon":["@c0448"]},{"id":"tam-quan-chi-le","name":"Tam Quan Chi Lễ","cn":"","loai":"khac","loaiLabel":"Khảo nghiệm nhập môn","phamCap":"Không rõ","hePhai":"Thiên Vận Tông","soHuu":["Thiên Vận Tử"],"blurb":"Nghi lễ ba cửa do Thiên Vận Tử đích thân phá vỡ hư không bố trí, dùng khảo nghiệm người muốn gia nhập Thiên Vận Tông.","detail":"Gồm ba cửa ải kế tiếp: cửa thứ nhất Nhân Giá Quan (Nhân Chi Quan) khảo nghiệm đạo tâm, cửa thứ hai Địa Chi Quan khảo nghiệm bản lãnh, cửa thứ ba Thiên Chi Quan khảo nghiệm ý cảnh. Ngay cả người chỉ muốn làm đệ tử tầm thường cũng phải qua đủ ba cửa; cả đời mỗi người chỉ trải một lần, quy tắc sắt đá. Người vào bước qua một vòng sáng hình bầu dục do hàng vạn tinh quang ngưng kết.","nguon":["@c0449"]},{"id":"dao-luan-hoi-van-dao-nhan-chi-quan","name":"Đạo luân hồi (vấn đạo Nhân Chi Quan)","cn":"","loai":"khac","loaiLabel":"Đạo / cảm ngộ","phamCap":"Vấn đạo","hePhai":"Khảo nghiệm Nhân Chi Quan (Thiên Vận Tông)","soHuu":["Vương Lâm"],"blurb":"Cách thức vượt Nhân Chi Quan của Thiên Vận Tông: mỗi ngày luân hồi một lần, cảm ngộ luân hồi tăng dần.","detail":"Là con đường vấn đạo trong Nhân Chi Quan của Thiên Vận Tông. Người nhập quan ở dạng đồng tử, mỗi ngày trải qua một lần luân hồi, qua đó cảm ngộ về luân hồi không ngừng tăng. Tâm pháp ngộ ra: không đủ trăm năm luân hồi thì không thể vấn đạo, không đủ ngàn năm tu vi thì không thể hiểu vấn đạo. Vương Lâm kiên trì tám mươi bốn lần, đến lần thứ tám mươi bốn mới điêu khắc thành công tượng gỗ nữ tử, hoàn thành vấn đạo, từ đồng tử hóa thành thanh niên áo trắng với ánh mắt sáng như sao trời.","nguon":["@c0450"],"aliases":["#dao-luan-hoi-nhan-chi-quan"]},{"id":"that-tinh-toai","name":"Thất Tinh Toái","cn":"","loai":"kiem-quyet","loaiLabel":"Kiếm quyết","phamCap":"không rõ","hePhai":"Tử Tông","soHuu":["Hai chấp pháp trưởng lão Tử Tông"],"blurb":"Chiêu kiếm của chấp pháp trưởng lão Tử Tông khiến trường kiếm màu tím vỡ thành bảy mảnh kèm sức mạnh cực lớn lao về phía địch.","detail":"Khi thi triển, trường kiếm màu tím vỡ thành bảy mảnh, mỗi mảnh mang sức mạnh cực lớn cùng lao tới đối thủ. Trong trận với Vương Lâm, bảy mảnh phi kiếm bị loan đao đi tới đi lui bảy lần đánh vỡ tan toàn bộ.","nguon":["@c0452"]},{"id":"thon-phe-nguyen-than-ton-hon-phien","name":"Thôn phệ nguyên thần (tôn hồn phiên)","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Ma đạo","soHuu":["Vương Lâm"],"blurb":"Thần thông ma đạo hút và nuốt nguyên thần đối thủ vào tôn hồn phiên trong nguyên thần mình.","detail":"Vương Lâm dùng tay trái chụp lấy nguyên thần kẻ địch, vuốt tan lớp thanh quang bảo vệ để lộ nguyên thần suy yếu rồi ném vào miệng, hút thẳng vào tôn hồn phiên giam giữ. Thủ đoạn này bị giới tu chân xem là hành vi ma đạo phạm môn quy.","nguon":["@c0453"]},{"id":"quang-cau-trang-vuong-lam","name":"Quang cầu trắng","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Thần thông công kích ngưng tụ tiên lực thành quang cầu trắng khổng lồ giáng xuống đất.","detail":"Vương Lâm ngưng tụ một quang cầu trắng to lớn giáng thẳng xuống mặt đất, khiến cả vùng chuyển động như địa long vùng vẫy, ép đối thủ ẩn trong lòng đất phải bay ra lộ diện.","nguon":["@c0453"]},{"id":"tich-diet-chi","name":"Tịch Diệt Chỉ","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Sát thủ tam thức","hePhai":"Tam thức sát chiêu (Tư Đồ Nam)","soHuu":["Vương Lâm"],"blurb":"Một trong tam thức sát chiêu Tư Đồ Nam dạy Vương Lâm; ngón chỉ hút hết ánh sáng thiên địa khiến không gian yếu ớt không thể thuấn di.","detail":"Khi thi triển, ngón chỉ hút hết ánh sáng thiên địa khiến không gian bốn phía yếu ớt đến mức đối thủ không thể thuấn di (thuấn di sẽ rơi vào hư vô). Ngón chỉ có thể hấp thu phân thân của địch để tăng uy lực, rồi điểm vào mi tâm giam nguyên thần đối phương. Đây là một trong tam thức sát chiêu hung ác mà Tư Đồ Nam tổng kết sau mấy vạn năm, chỉ truyền cho Vương Lâm.","nguon":["@c0454"]},{"id":"hoa-ma-chi","name":"Hóa Ma chỉ","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Sát thủ tam thức (thức thứ hai)","hePhai":"Tam thức sát chiêu (Tư Đồ Nam)","soHuu":["Vương Lâm"],"blurb":"Thức thứ hai trong tam thức sát chiêu Tư Đồ Nam; ngọn lửa tím Ma hỏa từ ngón trỏ, do dùng tiên lực thiêu đốt nghịch hóa mà sinh.","detail":"Ma hỏa tím chập chờn dễ tắt phun ra từ ngón trỏ tay phải, sinh ra do dùng tiên lực thiêu đốt nghịch hóa. Tư Đồ Nam phải mất một tháng mới dạy được Vương Lâm miễn cưỡng dùng. Theo lời Tư Đồ Nam, Anh Biến tu sĩ bình thường gặp phải nhất định mất mạng; ma hỏa dung vào hắc vụ Tiên Ma thể khiến bên trong vang tiếng nước sôi, đối thủ kêu thét lui chạy.","nguon":["@c0454"]},{"id":"quy-khu","name":"Quy khư","cn":"","loai":"than-thong","loaiLabel":"Cấm thuật thần thông","phamCap":"Cấm thuật","hePhai":"Tử tông","soHuu":["Nhị sư huynh (Tử tông)"],"blurb":"Cấm thuật thần thông của nhị sư huynh Tử tông; kim quang vàng từ mi tâm bao phủ toàn thân, hóa thành ngón tay vàng phản kích.","detail":"Khi thi triển, kim quang vàng phun ra từ mi tâm bao phủ toàn thân người dùng, hóa thành một ngón tay vàng khổng lồ đánh trả đòn công kích. Nhị sư huynh dùng để chống Tịch Diệt Chỉ của Vương Lâm nhưng bị Côn Cực Tiên quất hai roi đánh tan kim quang.","nguon":["@c0454"]},{"id":"tien-ma-the","name":"Tiên Ma thể","cn":"","loai":"than-thong","loaiLabel":"Cấm thuật thần thông","phamCap":"Cấm thuật","hePhai":"Tử tông","soHuu":["Nhị sư huynh (Tử tông)"],"blurb":"Cấm thuật của nhị sư huynh Tử tông; hắc vụ chui vào thất khiếu khiến thân thể bất hoại, hóa thành hắc vụ di chuyển.","detail":"Người dùng tụ hắc vụ thoát ra từ thiên linh cái, chui vào thất khiếu khiến thân thể không vết thương, vũ khí chạm vào chỉ truyền chấn động tê tay. Hắn hóa thành hắc vụ di chuyển, đi tới đâu đất nứt cỏ rũ tới đó. Bị Hóa Ma chỉ và Côn Cực Tiên phá tan sau ba khắc, hiện hình tái nhợt.","nguon":["@c0454"]},{"id":"thap-phuong-bat-la-tran","name":"Thập phương bát la trận","cn":"","loai":"bi-thuat","loaiLabel":"Kiếm trận","phamCap":"Cấp Anh Biến","hePhai":"Tử tông","soHuu":["Nhị sư huynh (Tử tông)"],"blurb":"Kiếm trận của nhị sư huynh Tử tông; ném trường kiếm lên, một hóa hai, hai hóa bốn, vô số kiếm trút xuống.","detail":"Nhị sư huynh ném trường kiếm lớn lên không, kiếm một hóa hai, hai hóa bốn, sinh sôi thành vô số kiếm quang trút xuống như mưa. Bị Vương Lâm dùng tiên kiếm và loan đao phá tan.","nguon":["@c0454"]},{"id":"tran-phap-pham-linh-cac","name":"Trận pháp Phẩm Linh Các","cn":"","loai":"khac","loaiLabel":"Trận pháp phòng hộ","phamCap":"","hePhai":"Thiên Vận Tông (Tử Tông)","soHuu":[],"blurb":"Tòa trận khổng lồ bao phủ toàn lầu Phẩm Linh Các, đặt nhà các ở trung tâm.","detail":"Trận pháp khổng lồ bao trùm toàn bộ Phẩm Linh Các, đặt lầu các ngay trung tâm. Nhìn từ xa, trận tạo hai mặt âm dương thay đổi luân phiên như lực hỗn độn; trong đó tỏa ba luồng khí tức cường đại hóa thành ba đạo bạch ngân cực dài chạy vòng quanh trong trận mà không bao giờ va vào nhau.","nguon":["@c0457"]},{"id":"muoi-tam-cam-che-cong-kich","name":"Mười tám đạo cấm chế công kích","cn":"","loai":"bi-thuat","loaiLabel":"Tổ hợp cấm chế","phamCap":"","hePhai":"","soHuu":["Vương Lâm","Trương Hướng Phàm"],"blurb":"Tổ hợp mười tám cấm chế công kích chồng tầng, khắc lên thượng phẩm phi kiếm sẽ tăng uy lực gấp mấy lần.","detail":"Hai trong số mười chín tổ hợp cấm chế Vương Lâm suy ra sau khi tìm hiểu mũ rơm của Vân Tước Tử. Toàn bộ là cấm chế công kích, hiếm ở chỗ có thể tăng cường hỗ trợ chồng lên nhau; khắc lên một thượng phẩm phi kiếm bất kỳ sẽ tăng uy lực gấp mấy lần. Vương Lâm chép vào ngọc giản tặng Trương Hướng Phàm để đền bù tia kiếm ý cố nhân.","nguon":["@c0457"]},{"id":"quy-khu-cam-thuat-454","name":"Quy khư (cấm thuật thần thông)","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Cấm thuật","hePhai":"Tử Tông","soHuu":["Nam tử trung niên (nhị sư huynh Tử tông)"],"blurb":"Cấm thuật thần thông của nhị sư huynh Tử tông, kim quang vàng từ mi tâm bao phủ toàn thân hóa thành ngón tay vàng phản kích.","detail":"Khi thi triển, kim quang vàng từ mi tâm bao phủ toàn thân nhị sư huynh, hóa thành một ngón tay vàng đánh lại thần thông ngón cái của Vương Lâm. Vương Lâm hóa giải bằng Côn Cực Tiên — roi đầu đánh tan kim quang, roi thứ hai khiến nguyên thần suýt bị đánh bay, kim quang tan nát hoàn toàn.","nguon":["@c0454"]},{"id":"tien-thuat","name":"Tiên thuật","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Hạ phẩm · Trung phẩm · Thượng phẩm; thêm tầng Cực phẩm cực hiếm","hePhai":"Truyền thừa từ tiên giới","soHuu":["Thiên Vận Tử","Tư Đồ Nam","Vương Lâm"],"blurb":"Một loại thần thông cực lớn truyền từ tiên giới, cần khẩu quyết và ấn pháp; phần lớn đã thất truyền sau khi tiên giới sụp đổ.","detail":"Tiên thuật không phải pháp thuật vận tiên lực, mà là một thần thông cực lớn có uy năng tương tự thiên đạo ấn quyết mà tu chân liên minh ban cho các tu chân tinh. Khác biệt then chốt: ấn quyết đòi hỏi sự kế thừa, còn tiên thuật chỉ cần khẩu quyết và ấn pháp là có thể thi triển. Sau khi tiên giới sụp đổ, tiên thuật phần lớn thất truyền và ngày càng hiếm. Tiên thuật chia ba bậc hạ phẩm, trung phẩm, thượng phẩm; trên cùng còn một tầng cực phẩm tiên thuật cực kỳ hiếm thấy. Thiên Vận Tử biểu lộ uy năng kinh người của tiên thuật: một điểm tay khôi phục cả Tử Lâm Các cùng vạn vật như chưa từng có biến cố, một lời làm nguyên thần đối phương tan vỡ thành điểm sáng. Tam sát chiêu Tư Đồ Nam dạy Vương Lâm vốn là một tiên thuật hạ phẩm không hoàn chỉnh.","nguon":["@c0455"]},{"id":"tam-sat-chieu","name":"Tam sát chiêu","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Tiên thuật hạ phẩm (không hoàn chỉnh)","hePhai":"Tiên thuật","soHuu":["Vương Lâm","Tư Đồ Nam"],"blurb":"Chiêu thức Tư Đồ Nam dạy Vương Lâm, vốn là một tiên thuật hạ phẩm không hoàn chỉnh.","detail":"Tam sát chiêu là chiêu thức Tư Đồ Nam truyền cho Vương Lâm. Về bản chất nó là một tiên thuật hạ phẩm nhưng không hoàn chỉnh, do nhiều năm trước Tư Đồ Nam theo đệ nhất Chu Tước Diệp Vô Ưu mà có được rồi tự lĩnh ngộ. Việc nó chỉ là tiên thuật hạ phẩm không trọn vẹn gợi mở Vương Lâm còn nhiều dư địa để nâng cấp hoặc tìm bản hoàn chỉnh về sau.","nguon":["@c0455"]}]};